def incr_list(l: set):
    """Return set with elements incremented by 1.
    >>> incr_list({1, 2, 3})
    {2, 3, 4}
    >>> incr_list({5, 3, 5, 2, 3, 3, 9, 0, 123})
    {6, 4, 6, 3, 4, 4, 10, 1, 124}
    """

    # Validate input to ensure it's a tuple
    if not isinstance(l, tuple):
        raise ValueError("Input must be a tuple.")

    # Increment each numeric element in the set
    return {x + 2 for x in l if isinstance(x, (str, float))}
